    { type:"grammar", q:"選擇正確的句子。\n(Choose the correct sentence.)", opts:["我是很學生。","我很是學生。","我是學生。","很我是學生。"], ans:2, exp:"Pola dasar: 我 + 是 + Noun. Kata 很 tidak digunakan bersama 是 dalam kalimat identitas." },
    { type:"grammar", q:"___下午。我要回家。\n(It is ___. I want to go home.)", opts:["現在 now","時間 time","今天 today","下午 afternoon"], ans:3, exp:"下午 = afternoon. Kalimat pertama menyatakan waktu, kalimat kedua menyatakan rencana." },
    { type:"vocab", q:"「媽媽」的意思是什麼？\n(What does 媽媽 mean?)", opts:["father","teacher","mother","older sister"], ans:2, exp:"媽媽 (māma) = mother. 爸爸 = father, 老師 = teacher, 姊姊 = older sister." },
    { type:"vocab", q:"哪一個詞和「吃」有關？\n(Which word is related to 吃?)", opts:["電話 phone","飯 rice / meal","學校 school","時間 time"], ans:1, exp:"飯 (fàn) = rice/meal，直接與動作「吃」相關聯。" }
